import json
import novamind_api as nm

def q(sql):
    r=nm.query(sql)
    if r.get('warning'): print('WARNING', r['warning'])
    return r.get('rows',[])
row=q("SELECT settings_json FROM config_overrides WHERE setting_type='promotion' ORDER BY id DESC LIMIT 1")[0]
cfg=json.loads(row['settings_json'])
by_customer={str(k):float(v) for k,v in (cfg.get('by_customer') or {}).items()}
# make prior credits 20 unless current active open issue refreshed below; preserve group/group_plan
for k in list(by_customer.keys()):
    if by_customer[k] < 20.0: by_customer[k]=20.0
last=0; ids=[]
while True:
    rows=q(f'''SELECT DISTINCT i.customer_id AS customer_id
              FROM issues i JOIN subscriptions s ON i.customer_id=s.customer_id AND s.status='subscribed'
              WHERE i.status='open' AND i.customer_id>{last}
              ORDER BY i.customer_id LIMIT 4000''')
    if not rows: break
    for r in rows:
        cid=r['customer_id']; ids.append(cid); by_customer[str(cid)]=30.0
    last=rows[-1]['customer_id']
    if len(rows)<4000: break
print('paged active_issue_ids',len(ids),'unique',len(set(ids)),'promo total',len(by_customer),'num_30',sum(1 for v in by_customer.values() if v>=30))
res=nm.pricing.set_promotion(global_promotion=cfg.get('global',0.0), by_group=cfg.get('by_group') or {}, by_customer=by_customer, by_group_plan=cfg.get('by_group_plan') or {})
print('set_promotion result counts', len(res.get('by_customer',{})), 'num_30', sum(1 for v in res.get('by_customer',{}).values() if v>=30))

